  "properties": {
    "parallel_trials": {
      "type": "integer",
      "minimum": 1,
      "description": "Maximum trials in flight simultaneously."
    },
    "max_trials": {
      "type": "integer",
      "minimum": 1,
      "description": "Hard ceiling on trials attempted."
    },
    "max_wall_time": {
      "type": "string",
      "pattern": "^[1-9][0-9]*[smhd]$",
      "description": "Hard ceiling on elapsed wall time; format is a positive integer followed by one of s, m, h, d."
    },
    "metrics_schema": {
