      "properties": {
        "expr": {
          "type": "string",
          "minLength": 1,
          "description": "Scalar expression over fields of metrics_schema."
        },
        "direction": {
          "type": "string",
          "enum": ["maximize", "minimize"]
        }
      }
    },
    "convergence_window": {
      "type": "integer",
      "minimum": 1,
